package redis

import (
	time_ "time"

	"github.com/huyungtang/go-lib/cache"
)

// constants & variables ******************************************************************************************************************
// ****************************************************************************************************************************************
// ****************************************************************************************************************************************

// public functions ***********************************************************************************************************************
// ****************************************************************************************************************************************
// ****************************************************************************************************************************************

// DefaultOption
// ****************************************************************************************************************************************
func DefaultOption(fn defaultFunc) Option {
	return &defaultOption{fn: fn}
}

// ExpireOption
// ****************************************************************************************************************************************
func ExpireOption(exp int64) Option {
	return &expireOption{exp: exp}
}

// ExpireAtOption
// ****************************************************************************************************************************************
func ExpireAtOption(tm time_.Time, isRenew bool) Option {
	return &expireOption{exp: tm.Unix(), isRenew: isRenew}
}

// ExpireDurationOption
// ****************************************************************************************************************************************
func ExpireDurationOption(dur string, isRenew bool) Option {
	d, e := time_.ParseDuration(dur)
	if e != nil {
		return nil
	}

	return &expireOption{exp: int64(d / time_.Second), isRenew: isRenew}
}

// ExpireRenewOption
// ****************************************************************************************************************************************
func ExpireRenewOption(exp int64) Option {
	return &expireOption{exp: exp, isRenew: true}
}

// ExpireImmedOption
// ****************************************************************************************************************************************
func ExpireImmedOption() Option {
	return &expireOption{exp: cache.Delete, isRenew: true}
}

// OverrideOption
// ****************************************************************************************************************************************
func OverrideOption(isOverride bool) Option {
	return &overrideOption{isOverride: isOverride}
}

// type defineds **************************************************************************************************************************
// ****************************************************************************************************************************************
// ****************************************************************************************************************************************

// Option
// ****************************************************************************************************************************************
type Option interface {
	Option()
}

// option *********************************************************************************************************************************
type option int

// option
// ****************************************************************************************************************************************
func (o *option) Option() {
}

// defaultOption **************************************************************************************************************************
type defaultOption struct {
	option
	fn defaultFunc
}

// defaultFunc ****************************************************************************************************************************
type defaultFunc func(interface{}) error

// expireOption ***************************************************************************************************************************
type expireOption struct {
	option
	exp     int64
	isRenew bool
}

// overrideOption *************************************************************************************************************************
type overrideOption struct {
	option
	isOverride bool
}

// private functions **********************************************************************************************************************
// ****************************************************************************************************************************************
// ****************************************************************************************************************************************
